/**
 * Extract the declaration block of the FIRST rule (within `text`) whose
 * selector matches `selectorRegex`, stopping at the first `}`. Returns null if
 * no such rule exists.
 *
 * This is the scoped generalization of `ruleDeclarations` below (which is
 * hard-wired to the whole stylesheet); it lets us look up a rule nested inside
 * an `@media` body.
 */
function declarationsIn(text: string, selectorRegex: RegExp): string | null {
  const re = new RegExp(selectorRegex.source + '\\s*\\{([^}]*)\\}');
  const m = text.match(re);
  return m ? m[1] : null;
}

function ruleDeclarations(selectorRegex: RegExp): string | null {
  return declarationsIn(CSS, selectorRegex);
}

/**
 * Extract the body of the FIRST `@media` rule whose media-condition targets
 * coarse-pointer / touch devices — i.e. references `(hover: none)` and/or
 * `(pointer: coarse)` — correctly handling the nested `{ ... }` rule blocks
 * inside a media query (a naive "stop at the first `}`" parse returns only a
 * fragment). Returns null if no such rule exists.
 *
 * Whitespace inside the condition is normalized before matching, so both
 * `(hover: none)` and `(hover:none)` (and likewise for `pointer: coarse`) are
 * accepted. The vitest environment does not load app.css and does not set any
 * emulated media features, so this text-parsing approach is the only way to
 * observe an `@media` rule.
 */
function coarsePointerMediaQueryBody(): string | null {
  const mediaRe = /@media\s+([^{}]*)\{/g;
  let m: RegExpExecArray | null;
  while ((m = mediaRe.exec(CSS)) !== null) {
    const condition = m[1].replace(/\s+/g, '');
    const targetsTouch =
      condition.includes('hover:none') || condition.includes('pointer:coarse');
    if (!targetsTouch) continue;
    const start = m.index! + m[0].length;
    let depth = 1;
    let i = start;
    while (i < CSS.length && depth > 0) {
      if (CSS[i] === '{') depth++;
      else if (CSS[i] === '}') depth--;
      i++;
    }
    if (depth !== 0) return null; // unbalanced braces — treat as not found
    return CSS.slice(start, i - 1);
  }
  return null;
}

